+/// Render a two-pane split frame: HUD left, event timeline right.
+pub fn render_split_frame_timeline(
+    frame: &mut ftui::Frame<'_>,
+    area: Rect,
+    ratio_percent: u16,
+    timeline: &mut TimelinePane,
+    events: &[ConsoleEvent],
